// Compatible con Twilio WhatsApp webhook
const body = $input.first().json.body;
const from = body.From || '';
const mensaje = body.Body || '';
const phone = from.replace('whatsapp:', '');

return [{ json: { phone, mensaje, timestamp: new Date().toISOString() } }];

const raw = $node['Cargar inventario de la tienda'].json.data;
const inventario = JSON.parse(Buffer.from(raw, 'base64').toString('utf8'));
return [{ json: { inventario_texto: JSON.stringify(inventario, null, 2) } }];

